21: // Provider wraps a providers.Interface to implement a grpc ProviderServer.
22: // This is useful for creating a test binary out of an internal provider
23: // implementation.
24: func Provider(p providers.Interface) tfplugin5.ProviderServer {
25: 	return &provider{
26: 		provider: p,
27: 		schema:   p.GetProviderSchema(),
28: 	}
29: }
