36: func (p *provider) GetMetadata(_ context.Context, req *tfplugin5.GetMetadata_Request) (*tfplugin5.GetMetadata_Response, error) {
37: 	return nil, status.Error(codes.Unimplemented, "GetMetadata is not implemented by core")
38: }
