40: func (p *provider) GetSchema(_ context.Context, req *tfplugin5.GetProviderSchema_Request) (*tfplugin5.GetProviderSchema_Response, error) {
41: 	resp := &tfplugin5.GetProviderSchema_Response{
42: 		ResourceSchemas:   make(map[string]*tfplugin5.Schema),
43: 		DataSourceSchemas: make(map[string]*tfplugin5.Schema),
44: 	}
45: 
46: 	resp.Provider = &tfplugin5.Schema{
47: 		Block: &tfplugin5.Schema_Block{},
48: 	}
49: 	if p.schema.Provider.Block != nil {
50: 		resp.Provider.Block = convert.ConfigSchemaToProto(p.schema.Provider.Block)
51: 	}
52: 
53: 	resp.ProviderMeta = &tfplugin5.Schema{
54: 		Block: &tfplugin5.Schema_Block{},
55: 	}
56: 	if p.schema.ProviderMeta.Block != nil {
57: 		resp.ProviderMeta.Block = convert.ConfigSchemaToProto(p.schema.ProviderMeta.Block)
58: 	}
59: 
60: 	for typ, res := range p.schema.ResourceTypes {
61: 		resp.ResourceSchemas[typ] = &tfplugin5.Schema{
62: 			Version: res.Version,
63: 			Block:   convert.ConfigSchemaToProto(res.Block),
64: 		}
65: 	}
66: 	for typ, dat := range p.schema.DataSources {
67: 		resp.DataSourceSchemas[typ] = &tfplugin5.Schema{
68: 			Version: dat.Version,
69: 			Block:   convert.ConfigSchemaToProto(dat.Block),
70: 		}
71: 	}
72: 	if decls, err := convert.FunctionDeclsToProto(p.schema.Functions); err == nil {
73: 		resp.Functions = decls
74: 	} else {
75: 		resp.Diagnostics = convert.AppendProtoDiag(resp.Diagnostics, err)
76: 		return resp, nil
77: 	}
78: 
79: 	resp.ServerCapabilities = &tfplugin5.ServerCapabilities{
80: 		GetProviderSchemaOptional: p.schema.ServerCapabilities.GetProviderSchemaOptional,
81: 		PlanDestroy:               p.schema.ServerCapabilities.PlanDestroy,
82: 		MoveResourceState:         p.schema.ServerCapabilities.MoveResourceState,
83: 	}
84: 
85: 	// include any diagnostics from the original GetSchema call
86: 	resp.Diagnostics = convert.AppendProtoDiag(resp.Diagnostics, p.schema.Diagnostics)
87: 
88: 	return resp, nil
89: }
