91: func (p *provider) PrepareProviderConfig(_ context.Context, req *tfplugin5.PrepareProviderConfig_Request) (*tfplugin5.PrepareProviderConfig_Response, error) {
92: 	resp := &tfplugin5.PrepareProviderConfig_Response{}
93: 	ty := p.schema.Provider.Block.ImpliedType()
94: 
95: 	configVal, err := decodeDynamicValue(req.Config, ty)
96: 	if err != nil {
97: 		resp.Diagnostics = convert.AppendProtoDiag(resp.Diagnostics, err)
98: 		return resp, nil
99: 	}
